import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  Box,
  Typography,
  useTheme,
} from '@mui/material';
import {
  Dashboard as DashboardIcon,
  Work as WorkIcon,
  People as PeopleIcon,
  Assessment as AssessmentIcon,
  Settings as SettingsIcon,
  ExitToApp as LogoutIcon,
} from '@mui/icons-material';
import { useAuth } from '../contexts/AuthContext';

const drawerWidth = 240;

const Sidebar: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const location = useLocation();
  const { user, logout } = useAuth();

  const handleNavigation = (path: string) => {
    navigate(path);
  };

  const handleLogout = async () => {
    try {
      await logout();
      navigate('/login');
    } catch (error) {
      console.error('Logout failed:', error);
    }
  };

  const adminItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/admin/dashboard' },
    { text: 'Jobs', icon: <WorkIcon />, path: '/admin/jobs' },
    { text: 'Candidates', icon: <PeopleIcon />, path: '/admin/candidates' },
    { text: 'Interview Results', icon: <AssessmentIcon />, path: '/admin/interview' },
    { text: 'Settings', icon: <SettingsIcon />, path: '/admin/settings' },
  ];

  const applicantItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/applicant/dashboard' },
    { text: 'Job Listings', icon: <WorkIcon />, path: '/jobs' },
    { text: 'My Applications', icon: <AssessmentIcon />, path: '/applicant/applications' },
  ];

  const items = user?.role === 'ADMIN' || user?.role === 'RECRUITER' ? adminItems : applicantItems;

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: drawerWidth,
        flexShrink: 0,
        '& .MuiDrawer-paper': {
          width: drawerWidth,
          boxSizing: 'border-box',
          backgroundColor: theme.palette.background.paper,
          borderRight: `1px solid ${theme.palette.grey[200]}`,
        },
      }}
    >
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: theme.spacing(2),
          backgroundColor: theme.palette.primary.main,
          color: theme.palette.primary.contrastText,
        }}
      >
        <Typography variant="h6" noWrap component="div">
          Hunter AI Interview
        </Typography>
      </Box>
      <Divider />
      <List>
        {items.map((item) => (
          <ListItem
            button
            key={item.text}
            onClick={() => handleNavigation(item.path)}
            selected={location.pathname.startsWith(item.path)}
            sx={{
              '&.Mui-selected': {
                backgroundColor: theme.palette.primary.light,
                '&:hover': {
                  backgroundColor: theme.palette.primary.light,
                },
              },
              '&:hover': {
                backgroundColor: theme.palette.grey[100],
              },
            }}
          >
            <ListItemIcon
              sx={{
                color: location.pathname.startsWith(item.path)
                  ? theme.palette.primary.contrastText
                  : theme.palette.text.primary,
              }}
            >
              {item.icon}
            </ListItemIcon>
            <ListItemText
              primary={item.text}
              sx={{
                color: location.pathname.startsWith(item.path)
                  ? theme.palette.primary.contrastText
                  : theme.palette.text.primary,
              }}
            />
          </ListItem>
        ))}
      </List>
      <Divider />
      <List>
        <ListItem
          button
          onClick={handleLogout}
          sx={{
            '&:hover': {
              backgroundColor: theme.palette.grey[100],
            },
          }}
        >
          <ListItemIcon>
            <LogoutIcon />
          </ListItemIcon>
          <ListItemText primary="Logout" />
        </ListItem>
      </List>
    </Drawer>
  );
};

export default Sidebar;
